function calculateHealthRisk(inputs) {
  const { age, gender, smokingStatus, preExistingConditions, pm25Concentration, no2Concentration, mercuryConcentration, yearsExposed } = inputs;

  // Input validation and default values for safety
  if ([age, pm25Concentration, no2Concentration, mercuryConcentration, yearsExposed].some(isNaN) || age <= 0 || yearsExposed < 0) {
    return { overallRiskScore: 0, respiratoryRisk: 0, cardiovascularRisk: 0, neurologicalRisk: 0 };
  }

  // --- Baseline Risk & Demographic Factors ---
  let baseRisk = 1; // Starting point for risk multiplier

  // Age Factor (Older age increases risk)
  let ageFactor = 1;
  if (age >= 70) ageFactor = 1.8;
  else if (age >= 50) ageFactor = 1.4;
  else if (age >= 30) ageFactor = 1.1;

  // Gender Factor (Simplified: some studies show minor differences)
  let genderFactor = 1;
  if (gender === 'male') genderFactor = 1.05;

  // Smoking Status Factor (Significant impact)
  let smokingFactor = 1;
  if (smokingStatus === 'ex-smoker') smokingFactor = 1.7;
  else if (smokingStatus === 'current-smoker') smokingFactor = 2.5;

  // Pre-existing Conditions Factor (Major impact on specific systems)
  let respiratoryConditionFactor = 1;
  let cardiovascularConditionFactor = 1;
  if (preExistingConditions === 'respiratory') respiratoryConditionFactor = 2.2;
  else if (preExistingConditions === 'cardiovascular') cardiovascularConditionFactor = 2.2;
  else if (preExistingConditions === 'both') {
    respiratoryConditionFactor = 2.8;
    cardiovascularConditionFactor = 2.8;
  }

  // Years Exposed Factor (Cumulative effect)
  // Risk grows non-linearly with long-term exposure. Max out after 40-50 years.
  let yearsExposedFactor = 1 + Math.min(yearsExposed, 40) * 0.05;
  yearsExposedFactor = Math.min(yearsExposedFactor, 3.0); // Cap multiplier

  // --- Pollutant-Specific Risk Factors (Non-linear increase above WHO guidelines) ---
  const WHO_PM25_ANNUAL = 5; // µg/m³
  const WHO_NO2_ANNUAL = 10; // ppb
  const BASE_MERCURY_LIMIT = 1; // ng/m³ (approximate low level for concerns, for modelling)

  // PM2.5 Factor: Impacts respiratory and cardiovascular systems heavily
  let pm25RiskFactor = 0;
  if (pm25Concentration > WHO_PM25_ANNUAL) {
    pm25RiskFactor = Math.pow(pm25Concentration / WHO_PM25_ANNUAL, 1.5) * 0.8; // Exponential growth
  } else {
    pm25RiskFactor = (pm25Concentration / WHO_PM25_ANNUAL) * 0.2; // Minor risk below guideline
  }
  pm25RiskFactor = Math.min(pm25RiskFactor, 8); // Cap for extreme pollution

  // NO2 Factor: Impacts respiratory and cardiovascular systems
  let no2RiskFactor = 0;
  if (no2Concentration > WHO_NO2_ANNUAL) {
    no2RiskFactor = Math.pow(no2Concentration / WHO_NO2_ANNUAL, 1.3) * 0.6; // Exponential growth
  } else {
    no2RiskFactor = (no2Concentration / WHO_NO2_ANNUAL) * 0.1; // Minor risk below guideline
  }
  no2RiskFactor = Math.min(no2RiskFactor, 6); // Cap

  // Mercury Factor: Primarily neurological, but can have systemic effects
  let mercuryRiskFactor = 0;
  if (mercuryConcentration > BASE_MERCURY_LIMIT) {
    mercuryRiskFactor = Math.pow(mercuryConcentration / BASE_MERCURY_LIMIT, 1.7) * 1.0; // Strong exponential growth
  } else {
    mercuryRiskFactor = (mercuryConcentration / BASE_MERCURY_LIMIT) * 0.15; // Minor risk
  }
  mercuryRiskFactor = Math.min(mercuryRiskFactor, 9); // Cap for extreme levels

  // --- Calculate Specific System Risks (0-10 scale) ---
  let respiratoryRiskBase = 1.0; // Base value for 0-10 scale
  let cardiovascularRiskBase = 1.0;
  let neurologicalRiskBase = 0.5;

  // Respiratory Risk Calculation
  let respiratoryRisk = respiratoryRiskBase
    * ageFactor
    * genderFactor
    * smokingFactor
    * respiratoryConditionFactor
    * (1 + pm25RiskFactor * 0.6 + no2RiskFactor * 0.4)
    * yearsExposedFactor;
  respiratoryRisk = Math.min(respiratoryRisk, 10); // Cap at 10

  // Cardiovascular Risk Calculation
  let cardiovascularRisk = cardiovascularRiskBase
    * ageFactor
    * genderFactor
    * smokingFactor
    * cardiovascularConditionFactor
    * (1 + pm25RiskFactor * 0.7 + no2RiskFactor * 0.3)
    * yearsExposedFactor;
  cardiovascularRisk = Math.min(cardiovascularRisk, 10); // Cap at 10

  // Neurological Risk Calculation (mainly mercury)
  let neurologicalRisk = neurologicalRiskBase
    * ageFactor
    * (1 + mercuryRiskFactor)
    * yearsExposedFactor;
  neurologicalRisk = Math.min(neurologicalRisk, 10); // Cap at 10

  // --- Overall Risk Score (0-100 scale) ---
  // Weighted average, giving more weight to respiratory/cardiovascular due to prevalence
  let overallRiskScore = (
    respiratoryRisk * 0.4 + 
    cardiovascularRisk * 0.4 + 
    neurologicalRisk * 0.2
  ) * 10; // Scale to 0-100

  overallRiskScore = Math.min(overallRiskScore, 100); // Cap at 100

  // Ensure all outputs are non-negative
  return {
    overallRiskScore: Math.max(0, overallRiskScore),
    respiratoryRisk: Math.max(0, respiratoryRisk),
    cardiovascularRisk: Math.max(0, cardiovascularRisk),
    neurologicalRisk: Math.max(0, neurologicalRisk)
  };
}
